@inherits LayoutComponentBase
@inject sv_da52a0f723ef45e9909c1e4be7f83f7a.Services.WizardStateStore WizardStore
@inject IHttpContextAccessor HttpContextAccessor

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (_currentStep > 0)
            {
                <div class="wizard-progress d-flex align-items-center gap-3 w-100">
                    <span class="fw-bold">Step @_currentStep of 4</span>
                    <div class="progress flex-grow-1" style="height: 8px;">
                        <div class="progress-bar" role="progressbar"
                             style="width: @(_currentStep * 25)%"
                             aria-valuenow="@_currentStep" aria-valuemin="0" aria-valuemax="4">
                        </div>
                    </div>
                </div>
                <nav class="wizard-nav d-flex gap-2 ms-3">
                    @for (int i = 1; i <= 4; i++)
                    {
                        var step = i;
                        var url = step switch
                        {
                            1 => "/apply/personal-info",
                            2 => "/apply/experience",
                            3 => "/apply/references",
                            _ => "/apply/review"
                        };
                        var label = step switch
                        {
                            1 => "Personal",
                            2 => "Experience",
                            3 => "References",
                            _ => "Review"
                        };
                        var isActive = step == _currentStep;
                        var isCompleted = step <= _completedStep;
                        <a href="@url"
                           class="btn btn-sm @(isActive ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary")">
                            @label
                        </a>
                    }
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private int _currentStep;
    private int _completedStep;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is null) return;

        var path = httpContext.Request.Path.Value ?? "";
        _currentStep = path switch
        {
            "/apply/personal-info" => 1,
            "/apply/experience" => 2,
            "/apply/references" => 3,
            "/apply/review" => 4,
            _ => 0
        };

        if (_currentStep > 0)
        {
            var sessionId = httpContext.Session.Id;
            var data = WizardStore.GetOrCreate(sessionId);
            _completedStep = data.CompletedStep;
        }
    }
}

@page "/apply/personal-info"
@layout sv_da52a0f723ef45e9909c1e4be7f83f7a.Components.Layout.ApplyLayout
@rendermode InteractiveServer

@inject sv_da52a0f723ef45e9909c1e4be7f83f7a.Services.WizardStateStore WizardStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<PageTitle>Apply - Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<EditForm Model="_model" OnValidSubmit="HandleNext" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="_model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private PersonalInfo _model = new();
    private string? _sessionId;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _sessionId = httpContext.Session.Id;
            var data = WizardStore.GetOrCreate(_sessionId);
            _model = data.PersonalInfo;
        }
    }

    private void HandleNext()
    {
        if (_sessionId is null) return;

        var data = WizardStore.GetOrCreate(_sessionId);
        data.PersonalInfo = _model;
        if (data.CompletedStep < 1) data.CompletedStep = 1;
        WizardStore.Save(_sessionId, data);

        Navigation.NavigateTo("/apply/experience");
    }
}

