@page "/apply/review"
@layout sv_da52a0f723ef45e9909c1e4be7f83f7a.Components.Layout.ApplyLayout
@rendermode InteractiveServer

@inject sv_da52a0f723ef45e9909c1e4be7f83f7a.Services.WizardStateStore WizardStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

@using sv_da52a0f723ef45e9909c1e4be7f83f7a.Services

<PageTitle>Apply - Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

@if (_data is not null)
{
    <div class="card mb-4 p-3">
        <h4>Personal Information</h4>
        <p><strong>Name:</strong> @_data.PersonalInfo.Name</p>
        <p><strong>Email:</strong> @_data.PersonalInfo.Email</p>
    </div>

    <div class="card mb-4 p-3">
        <h4>Job History</h4>
        @if (_data.Experience.Count == 0)
        {
            <p class="text-muted">No entries provided.</p>
        }
        else
        {
            @foreach (var job in _data.Experience)
            {
                <div class="border-bottom pb-2 mb-2">
                    <p><strong>@job.Title</strong> at @job.Company (@job.Duration)</p>
                </div>
            }
        }
    </div>

    <div class="card mb-4 p-3">
        <h4>References</h4>
        @if (_data.References.Count == 0)
        {
            <p class="text-muted">No references provided.</p>
        }
        else
        {
            @foreach (var r in _data.References)
            {
                <div class="border-bottom pb-2 mb-2">
                    <p><strong>@r.Name</strong> — @r.Email (@r.Relationship)</p>
                </div>
            }
        }
    </div>

    <div class="d-flex gap-2">
        <button type="button" class="btn btn-secondary" @onclick="HandleBack">← Back</button>
        <button type="button" class="btn btn-success" @onclick="HandleSubmit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">Application submitted successfully!</div>
    }
}

@code {
    private WizardData? _data;
    private string? _sessionId;
    private bool _submitted;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _sessionId = httpContext.Session.Id;
            _data = WizardStore.GetOrCreate(_sessionId);
        }
    }

    private void HandleBack()
    {
        Navigation.NavigateTo("/apply/references");
    }

    private void HandleSubmit()
    {
        _submitted = true;
        if (_sessionId is not null)
        {
            var data = WizardStore.GetOrCreate(_sessionId);
            data.CompletedStep = 4;
            WizardStore.Save(_sessionId, data);
        }
    }
}

